form:Form.form:Scripts:
		function Find()
{
	Ctrl("Conceptos").filter("",Ctrl("iter_search").GetCValue());
}

function ClearCONC()
{
	Ctrl("CONC").DelAllRow();
	Ctrl("Conceptos").Refresh();
}

function FullCONC()
{
	Ctrl("CONC").DelAllRow();     
	for (var t=0; t<Ctrl("Conceptos").TotalRowsCount(); t++)
		Ctrl("CONC").AddRow().SetAttr("id", Ctrl("Conceptos").GetAttrValue(t, "id"));

	Ctrl("Conceptos").Refresh();
}

function SetDates()
{
	var fechas;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	if(Ctrl("oi_liquidacion").GetXValue() != "")
	{	
		fechas = nSQL.GetOBJ(Ctrl("main").getResource("QRY_FECHAS"), "<PARAM oi_liquidacion=\""+Ctrl("oi_liquidacion").GetXValue()+"\" />"); 				
		Ctrl("f_desde").SetXValue(fechas.f_fechainicio);				
		Ctrl("f_hasta").SetXValue(fechas.f_fechafin);
		Ctrl("f_ini").SetXValue(fechas.f_fechainicio);				
		Ctrl("f_fin").SetXValue(fechas.f_fechafin);
	}

}

function LoadForm()   
{                     
	SetDates();                      
}   


