function ValidarFiltros()
{
	var boolFechas=false;
	var boolProcesamientos=false;
	var procesamientos="";

	//Valida el Filtro de las Fechas
	if(Ctrl("f_desde").GetXValue()=="" || Ctrl("f_hasta").GetXValue()=="")
		boolFechas=false;
	else
		boolFechas=true;              

	//Valida el Filtro de los Procesamientos
	for(i=0; i<Ctrl("grdProc").TotalRowsCount(); i++)
	{
		if(procesamientos=="")
			procesamientos=Ctrl("grdProc").GetCellXValue("oi_liq",i);
		else
			procesamientos=procesamientos+","+Ctrl("grdProc").GetCellXValue("oi_liq",i);
	}

	if(procesamientos=="")
		boolProcesamientos=false;
	else
		boolProcesamientos=true;

	//Valida ambos filtros en conjunto
	if(boolFechas==false && boolProcesamientos==false)
		return false;
	else
		return true;

}  

//Valida: si ingresa procesamiento y fechas - que ingrese fecha desde y fecha hasta - no una sola   
function ValidarFiltros2()
{
	var boolFechas=false;
	var procesamientos="";          

	for(i=0; i<Ctrl("grdProc").TotalRowsCount(); i++)
	{
		if(procesamientos=="")
			procesamientos=Ctrl("grdProc").GetCellXValue("oi_liq",i);
		else
			procesamientos=procesamientos+","+Ctrl("grdProc").GetCellXValue("oi_liq",i);
	}

	if(procesamientos!="" && Ctrl("f_desde").GetXValue()=="" && Ctrl("f_hasta").GetXValue()!="")
	{
		boolFechas=false;
	}
	else
	{
		if(procesamientos!="" && Ctrl("f_desde").GetXValue()!="" && Ctrl("f_hasta").GetXValue()=="")
		{
			boolFechas=false;
		}
		else
		{
			boolFechas=true;
		}
	}

	//Valida
	if(boolFechas==false)
		return false;
	else
		return true;

}  


function EditGrilla()
{
	//hidden procesamientos vacio
	Ctrl("procesamientos").SetXValue("");

	//Cargo hidden procesamientos con los valores de la grilla
	for(i=0; i<Ctrl("grdProc").TotalRowsCount(); i++)
	{
		if(Ctrl("procesamientos").GetXValue()=="")
			Ctrl("procesamientos").SetXValue(Ctrl("grdProc").GetCellXValue("oi_liq",i));
		else
			Ctrl("procesamientos").SetXValue(Ctrl("procesamientos").GetXValue()+","+Ctrl("grdProc").GetCellXValue("oi_liq",i));
	}           
}            

function ONLOAD_custom()
{                          
	EditGrilla();
}                                   

function CheckearTodos()
{
    chequear('1');
}                       

function DescheckearTodos()
{
    chequear('0');
}                  

function chequear(opcion)
{                                        
Ctrl('chkPuestoActual').SetXValue(opcion);  
Ctrl('chkPosicionActual').SetXValue(opcion);
Ctrl('chkDepartamentoActual').SetXValue(opcion);
Ctrl('chkSectorActual').SetXValue(opcion);
Ctrl('chkUbicacionActual').SetXValue(opcion);
Ctrl('chkCtroCostoActual').SetXValue(opcion);
}
